-- Incline Push-Up (incline-push-up)
UPDATE coaching.exercise SET
  name = 'Incline Push-Up',
  description = 'The athlete places hands on a bench or box, sets a braced plank line from head to heel, lowers chest toward the surface under control, and presses back to full elbow extension without sagging or flaring.',
  card_summary = 'Foundational Capacity push regression using an elevated surface to teach plank line, scapular control, and progressive horizontal pressing strength.',
  coach_language = 'Use as the foundational Capacity horizontal push. Progressive overload with full rest — not a warm-up fluff set or circuit finisher. Lower the incline only when every rep stays crisp.',
  athlete_language = 'Hands on the box, strong plank, lower your chest with control, and push the box away to stand tall in your line.',
  movement_family = 'Upper-body push strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'upper_body_push_strength',
  primary_order_slot = 'pushup_regression',
  default_sets = 3,
  default_reps = 8,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 40,
  movement_requirements = '{"primary_joint_actions":["shoulder_horizontal_adduction","shoulder_extension","elbow_extension","scapular_protraction"],"primary_tissues":["pectorals","anterior_deltoid","triceps","serratus_anterior","core"],"breathing_demand":"nasal","balance_demand":"stable","impact_level":0,"prerequisites":[],"setup_requirements":["Stable bench or box for incline and pike variations","Dumbbells, kettlebells, or bench as appropriate to variation","Clear floor space for push-up and floor-press patterns","Dip bars or rings at appropriate height for support holds"]}'::jsonb,
  coaching_execution = '{"movement_description":"Hands on elevated surface, braced plank line, controlled descent with elbows at roughly 45°, press to full extension without hip sag or rib flare.","setup":["Select stable bench or box height appropriate to skill.","Hands shoulder-width, fingers spread.","Walk feet back until plank line is straight.","Confirm pain-free range and supervision for youth."],"execution_steps":["Set braced plank — ribs down, glutes on.","Lower chest toward surface under control.","Keep elbows tracking — not flared to 90°.","Press through full hand to return to plank.","Finish with scapular protraction at top.","Rest fully before the next set."],"breathing_cues":["Inhale on descent — exhale through the press without losing brace."],"coach_cues":["Plank line.","Ribs down.","Elbows angle back.","Push the box away.","Control the descent."],"athlete_cues":["Tight core.","Down slow.","Push away.","Stay long."],"common_faults":["Hips sagging or piking.","Rib flare at bottom or top.","Elbows flaring to 90°.","Head dropping toward surface.","Rushing reps with short rest.","Lowering incline before control is earned."],"stop_signs":["Shoulder pinching during descent or press.","Wrist pain limiting hand support.","Cannot maintain plank line.","Sharp anterior shoulder pain.","Neck tension replacing scapular control."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Scapular Push-Up","Wrist Rockers","Wall Slides with Lift-Off","Dead Bug"],"pairs_well_after":["Push-Up","Tempo / Eccentric Push-Up","Dumbbell / Kettlebell Floor Press"],"good_for_sessions":["capacity_upper_body","push_capacity","strength_development"],"avoid_before":["Floor push-up if incline plank line is poor","Loaded bench press before horizontal push competency"],"avoid_after":[],"do_not_use_when":["Shoulder pinching every rep","Wrist pain with hand support","Using as conditioning circuit","Hip sag on every rep"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["NSCA push-up regression progressions","Incline push-up teaching for athletic populations"],"internal_notes":["Validator should confirm incline control before floor push-up or loaded press."]}'::jsonb,
  updated_at = now()
WHERE slug = 'incline-push-up';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'pushup_regression',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 2,
  fatigue_cost = 2,
  technical_complexity = 2,
  impact_level = 0,
  intensity_ceiling = 'moderate',
  notes = 'Foundational Capacity push regression. Master before floor push-up and loaded horizontal press. Supervision: recommended.'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'capacity'
JOIN coaching.phase_order_slot pos ON pos.key = 'pushup_regression' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'incline-push-up';

