JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum';

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'pregnancy_postpartum', 'pregnancy postpartum', 'baseline', v.guidance,
  CASE WHEN 'pregnancy_postpartum' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('incline-push-up', 'Elevated surface; avoid deep prone compression if uncomfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('push-up', 'Incline or elevated push-up if prone loading is uncomfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('tempo-eccentric-push-up', 'Incline tempo if prone floor work is uncomfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('dumbbell-kettlebell-floor-press', 'Reduce load; monitor supine symptoms — use incline press if needed.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('dumbbell-bench-press', 'Reduce load and ROM; use floor press if supine is uncomfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('half-kneeling-single-arm-press', 'Reduce load and ROM; avoid max overhead intent unless cleared.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('pike-push-up-box-pike-push-up', 'Avoid deep inverted loading unless cleared; use hands-elevated regression.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('dip-support-ring-support-hold', 'Avoid unsupported ring work unless cleared; use feet-assisted bar support.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('incline-push-up', 'Incline push-ups reduce the percentage of body weight on the hands while preserving the closed-chain pressing pattern. They build chest, shoulder, and triceps force capacity with trunk bracing demand relevant to tumbling, vaulting, and hand support without requiring floor push-up competency first.', 'Belongs in pushup_regression (431) — foundational Capacity horizontal push before floor push-up and loaded press work.', 'Primary entry in pushup_regression after Output; before floor push-up, loaded press, or inverted push when horizontal push mechanics are still developing.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not use as high-rep conditioning, allow hip sag every rep, or lower incline before plank line and scapular control are clean.', 'Regress to wall push-up or higher incline; progress to lower incline or floor push-up only when ribs stay down and elbows track. Hypermobility athletes need active serratus and rib control — no passive shoulder hang.'),
  ('push-up', 'The floor push-up loads the entire pressing chain — chest, shoulders, triceps, and trunk stabilizers — in a closed-chain pattern directly relevant to tumbling, vault push-off, and hand support. Capacity intent with tempo and full rest builds tissue reserve without the speed demand of Output plyometric pushes.', 'Belongs in horizontal_push_strength (432) — primary Capacity floor push after incline regression competency.', 'horizontal_push_strength after incline push-up competency; before tempo eccentric, floor press, or inverted push when floor push quality is established.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not rep out to failure with short rest, allow hip sag, or prescribe before incline push-up control is earned.', 'Regress to incline push-up; progress to tempo eccentric, weighted vest, or floor press only when plank line and elbow tracking stay clean. Use 45° elbow angle cue — not flared 90°.'),
  ('tempo-eccentric-push-up', 'Tempo and eccentric-emphasis push-ups increase time under tension on chest, shoulders, and triceps during the lowering phase. This builds tissue capacity and deceleration-relevant pressing strength when dosed conservatively with full rest — distinct from explosive Output push variations.', 'Belongs in push_eccentric (433) — eccentric Capacity push after floor push-up competency.', 'push_eccentric after floor push-up competency; useful when athletes need eccentric pressing strength without adding external load.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not bounce at bottom, rush the eccentric, prescribe before push-up control, or stack high volume before tumbling Output.', 'Regress to incline tempo push-up or eccentric-only to elevated surface; shorten eccentric duration before reducing incline height. Lower rep count than standard push-up.'),
  ('dumbbell-kettlebell-floor-press', 'The floor press limits shoulder extension ROM at the bottom, reducing anterior shoulder stress while still loading chest and triceps. It builds horizontal pressing force capacity with a clear depth reference and is a natural bridge from push-up to bench press progressions.', 'Belongs in horizontal_push_strength (432) — loaded horizontal Capacity push after push-up competency, before bench press.', 'horizontal_push_strength after push-up competency; before dumbbell bench press when athletes need loaded horizontal push with controlled ROM.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not bounce upper arms off floor, arch excessively, or prescribe before push-up control. Not a high-rep burnout set.', 'Regress to lighter load or neutral-grip dumbbells; progress load only when elbows track and trunk stays braced. Use tempo before load jumps.'),
  ('dumbbell-bench-press', 'Dumbbell bench press allows independent arm loading and natural wrist path while building chest, shoulder, and triceps force capacity through full ROM. It progresses horizontal pressing reserve beyond bodyweight and floor press when dosed with tempo and full rest.', 'Belongs in horizontal_push_strength (432) — loaded horizontal Capacity push after floor press or push-up competency.', 'horizontal_push_strength after floor press or push-up competency; primary loaded horizontal push when bench setup is available and shoulder tolerance allows full ROM.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not bounce off chest, use excessive arch, or prescribe before floor press or push-up control. Not a metcon with short rest.', 'Regress to floor press or lighter dumbbells; progress load only when elbows track and trunk stays braced. Use spotter or self-rack safely on heavy sets.'),
  ('half-kneeling-single-arm-press', 'Half-kneeling removes lower-body drive and increases demand on trunk anti-extension and anti-rotation while pressing overhead. It builds vertical pressing force capacity and shoulder stability relevant to handstand, tumbling overhead, and bar path control when progressed from horizontal push competency.', 'Belongs in vertical_push_strength (434) — primary Capacity vertical push after horizontal push base.', 'vertical_push_strength after horizontal push competency; primary vertical push entry before overhead barbell work when anti-extension and shoulder control are priorities.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not lean back to finish reps, use leg drive, or prescribe before push-up control. Not a push-press or jerk pattern.', 'Regress to tall-kneeling or lighter load; shorten ROM before adding weight. Complete all reps one side before switching or alternate by set — be consistent.'),
  ('pike-push-up-box-pike-push-up', 'Pike push-ups increase shoulder flexion demand and shift load toward deltoids and triceps in an inverted pressing angle relevant to handstand push-up progressions. Box elevation adjusts difficulty while preserving Capacity intent with controlled reps and full rest.', 'Belongs in inverted_push_strength (435) — inverted Capacity push after horizontal push base, before dip support and handstand Output.', 'inverted_push_strength after push-up and optional vertical press competency; before dip support or handstand Output when inverted push control is the goal.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not collapse into forward fold without shoulder load, rep out with short rest, or prescribe before push-up control. Not a handstand skill substitute.', 'Regress to box pike with hands elevated or feet on floor with shallow ROM; progress to feet-elevated pike only when head path and shoulder control stay clean. Use tempo before ROM depth increases.'),
  ('dip-support-ring-support-hold', 'Top-of-dip support holds train isometric pressing strength, scapular depression and protraction, and trunk bracing at a position relevant to ring work, bar support, and tumbling hand support. Capacity dosing with short holds and full rest builds support reserve before dynamic dip or ring Output work.', 'Belongs in support_strength (436) — isometric Capacity support after horizontal and inverted push base, before dip eccentrics or ring Output.', 'support_strength after push-up and pike push-up competency; end of push cluster or before dip eccentric progressions when support strength is the limiting factor.', 'Upper-body push Capacity builds pressing reserve with controlled load and full rest — not explosive Output pushes or high-rep Fitness circuits. Do not turn into high-rep dip eccentrics, allow shoulder shrug or elbow unlock, or prescribe before push-up and pike competency. Not a Control isometric in a warm-up circuit.', 'Regress to parallel bar support with feet assisted or shorter hold; progress hold time before adding ring instability. Use 10-second default holds with full rest.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Upper-body push Capacity cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'capacity_push_readiness',
  NULL,
  'Upper-Body Push Capacity without stealing hand-support quality',
  'Push Capacity needs intentional load, controlled reps, and full rest — not explosive Output pushes or high-rep Fitness circuits.',
  'Upper-body push cluster: incline push-up, push-up, tempo/eccentric push-up, floor press, dumbbell bench press, half-kneeling single-arm press, pike push-up, and dip/ring support hold.',
  'Pressing strength supports push-ups, crawling, hand support, cartwheels, handstands, dips, rings, and overhead work. Poor placement or wrist/shoulder fatigue reduces tumbling and hand-support skill quality.',
  'Place after Output unless strength-priority; master incline/floor push-up before pike and ring support; regress on wrist/shoulder pain; keep eccentric push volume conservative before hand-support skill.',
  'Do not program high-rep push circuits before handstand/tumbling skill, use pike push-ups without floor push-up competency, or finish sloppy push-up reps for Capacity intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
